const i = $input.first() ? ($input.first().json || {}) : {};
function pick(){ for(var k=0;k<arguments.length;k++){ var v=arguments[k]; if(v!=null && String(v).trim()!=='') return String(v).trim(); } return ''; }
let custom = pick(i['Custom topic']); let drop = pick(i['Topic'], i.topic); if(/^custom/i.test(drop)) drop='';
let t = pick(custom, drop, i.query, i.text); t = t.replace(/^\/[a-zA-Z]+\b/, '').trim();
if(!t) t = ($env.DEFAULT_AWARENESS_TOPIC || 'phishing');
const fmt = pick(i['Format'], i.format).toLowerCase();
let format='Both'; if(fmt.indexOf('scorm')>=0 && fmt.indexOf('html')<0) format='SCORM'; else if(fmt.indexOf('html')>=0 && fmt.indexOf('scorm')<0) format='HTML';
const pm = parseInt(pick(i['Pass mark (%)'], i['Pass mark'], i.passMark),10);
const imgSel = pick(i['Section images'], i.illustrate);
let illustrate; if(imgSel) illustrate = !/^(no|false|off|0)/i.test(imgSel); else illustrate = (($env.ELEARNING_SECTION_IMAGES||'true').toString().toLowerCase()!=='false');
// Learning Hub extras: a magazine-derived course passes grounding `source`, an
// explicit `title`, and the publication/course ids that tie completion back to
// the dashboard. When source/title are present the topic falls back to the title.
const source = pick(i.source, i.brief);
const title = pick(i.title);
if(!custom && !drop && title) t = title;
const publicationId = pick(i.publicationId);
const courseId = pick(i.courseId);
return [{ json: { topic:t, title:title, source:source, publicationId:publicationId, courseId:courseId, audience:(pick(i['Audience'],i.audience)||'All staff'), passMark:(isNaN(pm)?80:pm), format:format, illustrate:illustrate, date:new Date().toISOString().slice(0,10), client:($env.CLIENT_NAME||'').toString() } }];

parameters.jsonBody:
={
  "model": "{{ $env.CLAUDE_MODEL || 'claude-opus-4-8' }}",
  "max_tokens": 7000,
  "system": "You are an instructional designer creating a short interactive security-awareness e-learning module. For the given topic and audience produce a SINGLE valid JSON object. Keys: title; intro (2-3 sentences on why this matters to the learner and the organisation); sections (4-6 items, each {heading, body (2-4 short paragraphs separated by single newline characters), keyPoints (2-4 short bullet strings), scene (ONE vivid sentence describing a realistic modern-office scene that visually illustrates this section, written for an illustrator: describe the people, setting and action; do NOT mention any on-screen text, screens of text, or logos)}); questions (4-6 knowledge-check items, each {q, options (array of exactly 4 short strings), answer (0-based index of the correct option), why (one-sentence explanation)}); gameItems (10-12 items for an allow-or-block training game, each {text (a SHORT realistic message, request or behaviour a member of staff might encounter, max 100 characters - e.g. an email subject plus its ask, a caller request, or a workplace action - roughly half safe and half risky, drawn from this module's content), risky (true if it should be blocked, refused or reported; false if it is safe normal business), why (one sentence the learner sees after deciding)}). Plain, engaging, non-technical language tailored to the audience. Do NOT use markdown code fences. Output ONLY the JSON object.",
  "messages": [ {"role":"user","content": {{ JSON.stringify( ($json.source ? ('Base this module STRICTLY on the following staff security-awareness magazine content. Write a short course title, a 2-3 sentence intro, 4-6 sections and 4-6 multiple-choice questions grounded ONLY in it.\n\n' + $json.source) : ('Create an interactive e-learning module on the topic: ' + ($json.topic || 'phishing'))) + ' Audience: ' + ($json.audience || 'All staff') + '. Knowledge-check pass mark: ' + ($json.passMark || 80) + '%.' ) }} } ]
}

parameters.jsCode:
const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text;
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const r = $('Resolve Input').first().json;
const STYLE = 'Cinematic, semi-realistic editorial illustration set in a bright modern corporate office. Polished, professional and calm mood; soft natural window light with a warm key light; teal and deep-navy colour grade; shallow depth of field; clean wide composition with generous empty space near the top. Diverse professional people in business-casual attire, natural expressions. ';
const NEG = ' No text, no words, no letters, no numbers, no logos, no signage, no watermark, no user-interface screenshots, no charts.';
if (data && !data.title && r.title) data.title = r.title;
const sections = (data && data.sections) || [];
const imagePrompts = sections.map(function(s){ var scene = (s && (s.scene || s.heading)) || ('a workplace scene about ' + (r.topic||'security awareness')); return STYLE + 'Scene: ' + scene + '.' + NEG; });
const coverPrompt = 'Wide cinematic hero cover image for a premium corporate security-awareness course about ' + (r.topic||'security awareness') + '. ' + STYLE + 'Establishing wide shot of a modern office that conveys trust, focus and vigilance; dramatic but professional lighting; strong empty space on the left for a title.' + NEG;
return [{ json: { data:data, topic:r.topic, audience:r.audience, passMark:r.passMark, format:r.format, illustrate:r.illustrate, imagePrompts:imagePrompts, coverPrompt:coverPrompt, date:r.date, client:r.client, publicationId:r.publicationId, courseId:r.courseId } }];

const j = $json || {};
const sectionPrompts = j.imagePrompts || [];
const coverPrompt = j.coverPrompt || '';
let sections = sectionPrompts.map(function(){ return ''; });
let cover = '';
const key = $env.OPENAI_IMAGE_API_KEY || $env.OPENAI_API_KEY;
if (j.illustrate && key) {
  const H = this.helpers;
  const base = ($env.OPENAI_BASE_URL || 'https://api.openai.com/v1');
  const model = ($env.IMAGE_MODEL || 'gpt-image-2');
  const size = ($env.ELEARNING_IMAGE_SIZE || '1536x1024');
  const gen = async function(p){
    try {
      const resp = await H.httpRequest({ method:'POST', url: base + '/images/generations',
        headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
        body: { model: model, prompt: p, size: size, quality: ($env.ELEARNING_IMAGE_QUALITY || 'high'), n: 1 }, json: true, timeout: 180000 });
      const b64 = resp && resp.data && resp.data[0] && resp.data[0].b64_json;
      return b64 ? ('data:image/png;base64,' + b64) : '';
    } catch (e) { return ''; }
  };
  if (coverPrompt) cover = await gen(coverPrompt);
  for (let k = 0; k < sectionPrompts.length; k++) { sections[k] = await gen(sectionPrompts[k]); }
}
return [{ json: Object.assign({}, j, { images: { cover: cover, sections: sections } }) }];

// E-learning renderer — gamified 16:9 enterprise lesson player. Cover, name entry,
// mission briefing, animated sections (Ken Burns heroes, animated SVG accents),
// XP + levels + achievement badges, a playable three.js mini-game ("Firewall:
// Threat Storm" — allow/block AI-written threat statements flying at your
// firewall, with combos, integrity and educational feedback; 2D DOM fallback when
// WebGL is unavailable), knowledge check with animated score ring, confetti, and a
// bedded-in completion certificate. SCORM 1.2 aware (quiz score reported to LMS).
const d = $json.data || {};
const topic = $json.topic || 'Security Awareness';
const date = $json.date || new Date().toISOString().slice(0,10);
const client = ($json.client || '').toString();
const passMark = Number($json.passMark) || 80;
const format = $json.format || 'Both';
const images = ($json.images && typeof $json.images === 'object' && !Array.isArray($json.images))
  ? { cover: ($json.images.cover||''), sections: ($json.images.sections||[]) }
  : { cover:'', sections:(Array.isArray($json.images)?$json.images:[]) };
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
const title = d.title || (topic + ' — Awareness Module');
const brand = client ? client : 'Security Awareness';
const publicationId = ($json.publicationId || '').toString();
const courseId = ($json.courseId || '').toString();

// Env-driven brand theme (platform standard).
function jbHex(v,df){v=String(v||'').trim();return /^#[0-9a-fA-F]{6}$/.test(v)?v:df;}
var JB_PRI=jbHex($env.BRAND_PRIMARY,'#0A1A2F'),JB_ACC=jbHex($env.BRAND_ACCENT,'#0E7C86'),JB_GOLD=jbHex($env.BRAND_GOLD,'#C9A24B');

// three.js — vendored library inlined so the package is fully self-contained
// (works inside locked-down LMS networks); CDN fallback only if the mount is
// missing; the game itself degrades to a 2D DOM version when WebGL/THREE fail.
let _fs = null; try { _fs = require('fs'); } catch (e) {}
let THREE_SRC = '';
try { THREE_SRC = _fs.readFileSync('/config/vendor/three.min.js','utf8'); } catch (e) { THREE_SRC = ''; }

// --- animated SVG icon set (stroke = brand accent; .pz group is animated in CSS) ---
function ic(inner){ return '<svg viewBox="0 0 24 24" fill="none" stroke="'+JB_ACC+'" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><g class="pz">'+inner+'</g></svg>'; }
const ICONS = {
  shield: ic('<path d="M12 3l7 3v5c0 4.5-3 7.6-7 9-4-1.4-7-4.5-7-9V6z"/><path d="M9 12l2 2 4-4"/>'),
  lock:   ic('<rect x="5" y="11" width="14" height="9" rx="2"/><path d="M8 11V8a4 4 0 0 1 8 0v3"/>'),
  mail:   ic('<rect x="3" y="5" width="18" height="14" rx="2"/><path d="M3 7l9 6 9-6"/>'),
  eye:    ic('<path d="M2 12s4-7 10-7 10 7 10 7-4 7-10 7S2 12 2 12z"/><circle cx="12" cy="12" r="3"/>'),
  alert:  ic('<path d="M12 3l9 16H3z"/><path d="M12 10v4"/><circle cx="12" cy="16.7" r="0.6" fill="'+JB_ACC+'" stroke="none"/>'),
  key:    ic('<circle cx="8" cy="12" r="4"/><path d="M12 12h9M18 12v4M21 12v3"/>'),
  phone:  ic('<path d="M6 3h4l2 5-3 2a11 11 0 0 0 5 5l2-3 5 2v4a2 2 0 0 1-2 2A17 17 0 0 1 4 6a2 2 0 0 1 2-3z"/>'),
  id:     ic('<rect x="3" y="5" width="18" height="14" rx="2"/><circle cx="9" cy="11" r="2"/><path d="M14 10h4M14 13h4M6 16h8"/>'),
  check:  ic('<path d="M5 13l4 4 10-10"/>')
};
function pickIcon(h){ h=(h||'').toLowerCase();
  if(/phish|email|mail|bec|message|invoice/.test(h)) return 'mail';
  if(/password|mfa|auth|credential|key|login/.test(h)) return 'key';
  if(/call|phone|vish|voice/.test(h)) return 'phone';
  if(/pretext|imperson|identity|profile/.test(h)) return 'id';
  if(/spot|sign|watch|red flag|detect|recognis|recogniz/.test(h)) return 'eye';
  if(/report|incident|respond|attack|suspect|breach|fraud/.test(h)) return 'alert';
  if(/lock|secure|encrypt|device|protect|data/.test(h)) return 'lock';
  return 'shield';
}
const sections = (d.sections||[]).map(function(s){ var o=Object.assign({}, s); o.iconKey=pickIcon((s.heading||'')+' '+(s.scene||'')); return o; });
// Game items: AI-written allow/block statements. If the model returned none the
// mission is skipped gracefully (we never fabricate training content here).
const gameItems = (Array.isArray(d.gameItems)?d.gameItems:[]).map(function(g){ g=g||{}; return { text:String(g.text||'').trim().slice(0,120), risky:!!g.risky, why:String(g.why||'').trim() }; }).filter(function(g){ return g.text; }).slice(0,14);

// --- premium certificate furniture (gold seal, corner flourishes, crest, watermark) ---
function certInitials(s){ var w=String(s||'').trim().split(/\s+/).filter(Boolean); var a=(w[0]||'S')[0]+((w[1]||w[0]||'A')[0]||''); return a.toUpperCase().slice(0,2); }
function makeSeal(init, topText, botText){
  var cx=110, cy=104, spikes=30, R1=96, R2=86, pts=[];
  for(var i=0;i<spikes*2;i++){ var r=(i%2===0)?R1:R2; var a=(Math.PI/spikes)*i - Math.PI/2; pts.push((cx+r*Math.cos(a)).toFixed(1)+','+(cy+r*Math.sin(a)).toFixed(1)); }
  var burst='<polygon points="'+pts.join(' ')+'" fill="url(#gold)" stroke="#8A6A22" stroke-width="1"/>';
  function laurel(side){ var g='',n=8; for(var i=0;i<n;i++){ var t=i/(n-1); var ang=(-150 + t*120)*Math.PI/180; var rad=58; var x=cx + side*(rad*Math.cos(ang)*0.62 + 6); var y=cy + 30 - rad*Math.sin(ang)*0.95; var rot=(side>0?-50:50)+(t*60*side); g+='<ellipse cx="'+x.toFixed(1)+'" cy="'+y.toFixed(1)+'" rx="9" ry="3.6" fill="#E3C766" transform="rotate('+rot.toFixed(1)+' '+x.toFixed(1)+' '+y.toFixed(1)+')"/>'; } return g; }
  function star(scx,scy,R,r,p2){ var p=[]; for(var i=0;i<p2*2;i++){ var rr=(i%2===0)?R:r; var a=(Math.PI/p2)*i - Math.PI/2; p.push((scx+rr*Math.cos(a)).toFixed(1)+','+(scy+rr*Math.sin(a)).toFixed(1)); } return '<polygon points="'+p.join(' ')+'" fill="url(#gold)" stroke="#8A6A22" stroke-width="0.6"/>'; }
  return '<svg class="seal" viewBox="0 0 220 250" xmlns="http://www.w3.org/2000/svg">'
   +'<defs><radialGradient id="gold" cx="50%" cy="36%" r="68%"><stop offset="0" stop-color="#F6E6A8"/><stop offset="50%" stop-color="#D9B45A"/><stop offset="100%" stop-color="#A9842F"/></radialGradient></defs>'
   +'<path d="M83 150 L70 244 L98 222 L110 240 L122 222 L150 244 L137 150 Z" fill="'+JB_ACC+'"/>'
   +'<path d="M83 150 L78 186 L137 186 L137 150 Z" fill="#0a5b63"/>'
   +burst
   +'<circle cx="'+cx+'" cy="'+cy+'" r="80" fill="url(#gold)"/>'
   +'<circle cx="'+cx+'" cy="'+cy+'" r="72" fill="#0E2233"/>'
   +'<circle cx="'+cx+'" cy="'+cy+'" r="72" fill="none" stroke="#E3C766" stroke-width="2" stroke-dasharray="1.5 5"/>'
   +'<circle cx="'+cx+'" cy="'+cy+'" r="60" fill="none" stroke="#C9A24B" stroke-width="1"/>'
   +laurel(-1)+laurel(1)+star(cx,cy-18,16,7,5)
   +'<text x="'+cx+'" y="'+(cy+14)+'" text-anchor="middle" font-family="Georgia,serif" font-size="20" font-weight="bold" fill="#F6E6A8" letter-spacing="1">'+esc(init)+'</text>'
   +'<text x="'+cx+'" y="'+(cy+34)+'" text-anchor="middle" font-family="Arial,sans-serif" font-size="8.5" fill="#E3C766" letter-spacing="2">'+esc(botText)+'</text>'
   +'<text x="'+cx+'" y="'+(cy-44)+'" text-anchor="middle" font-family="Arial,sans-serif" font-size="9" fill="#E3C766" letter-spacing="3">'+esc(topText)+'</text>'
   +'</svg>';
}
function makeCorner(cls){ return '<svg class="cn '+cls+'" viewBox="0 0 80 80"><path d="M6 74 C6 36 36 6 74 6" fill="none" stroke="#C9A24B" stroke-width="2"/><path d="M14 74 C14 42 42 14 74 14" fill="none" stroke="#C9A24B" stroke-width="1"/><circle cx="6" cy="74" r="3.5" fill="#C9A24B"/></svg>'; }
const certSeal = makeSeal(certInitials(brand), 'CERTIFIED', 'EXCELLENCE');
const certCorners = makeCorner('tl')+makeCorner('tr')+makeCorner('bl')+makeCorner('br');
const certCrest = '<svg class="crest" viewBox="0 0 24 24" fill="none" stroke="'+JB_ACC+'" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M12 3l7 3v5c0 4.5-3 7.6-7 9-4-1.4-7-4.5-7-9V6z"/><path d="M9 12l2 2 4-4"/></svg>';
const certWm = '<svg class="wm" viewBox="0 0 24 24" fill="none" stroke="#0E2233" stroke-width="1"><path d="M12 3l7 3v5c0 4.5-3 7.6-7 9-4-1.4-7-4.5-7-9V6z"/><path d="M9 12l2 2 4-4"/></svg>';

const payload = { title:title, brand:brand, intro:(d.intro||''), sections:sections,
  questions:(d.questions||[]), game:gameItems, passMark:passMark, images:images, icons:ICONS,
  theme:{ pri:JB_PRI, acc:JB_ACC, gold:JB_GOLD },
  seal:certSeal, corners:certCorners, crest:certCrest, wm:certWm,
  publicationId:publicationId, courseId:courseId };
const dataJson = JSON.stringify(payload).replace(/</g,'\\u003c');

const CSS = `:root{--pri:${JB_PRI};--acc:${JB_ACC};--gold:${JB_GOLD}}
*{box-sizing:border-box} html,body{margin:0;height:100%} body{font-family:-apple-system,'Segoe UI',Arial,sans-serif;background:#0a141d;color:#14202b;display:flex;align-items:center;justify-content:center;overflow:hidden}
.stage{position:relative;width:min(100vw,177.78vh);height:min(56.25vw,100vh);background:#fff;display:flex;flex-direction:column;overflow:hidden;box-shadow:0 24px 70px rgba(0,0,0,.55)}
.top{display:flex;align-items:center;gap:13px;background:linear-gradient(135deg,#0E2233,var(--acc));color:#fff;padding:11px 22px;flex:0 0 auto}
.top .logo{width:28px;height:28px;flex:0 0 auto}
.top .tt{line-height:1.1;min-width:0}
.top .b{font-size:10px;letter-spacing:2px;text-transform:uppercase;color:#9fe4d8;font-weight:800}
.top h1{margin:2px 0 0;font-size:15px;font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.top .crumbs{margin-left:auto;font-size:11px;color:#bfe6df;letter-spacing:1px;white-space:nowrap}
.xpwrap{display:flex;align-items:center;gap:8px;margin-left:14px;flex:0 0 auto}
.lvl{font-size:10px;font-weight:800;letter-spacing:1px;background:var(--gold);color:#0E2233;border-radius:10px;padding:3px 9px;transition:transform .2s}
.lvl.pop{transform:scale(1.25)}
.xpbar{width:90px;height:7px;border-radius:4px;background:rgba(255,255,255,.18);overflow:hidden}
.xpbar span{display:block;height:7px;background:linear-gradient(90deg,#5FD0C0,var(--gold));width:0;transition:width .5s ease}
.xpn{font-size:10px;color:#cfe9e4;font-weight:700;min-width:46px}
.narr{margin-left:10px;display:inline-flex;align-items:center;gap:6px;background:rgba(255,255,255,.14);border:1px solid rgba(255,255,255,.32);color:#fff;border-radius:20px;padding:6px 12px;font-size:12px;font-weight:700;cursor:pointer;font-family:inherit;transition:background .15s}
.narr:hover{background:rgba(255,255,255,.26)}.narr svg{display:block}
.prog{height:5px;background:rgba(14,34,51,.12);flex:0 0 auto}.prog span{display:block;height:5px;background:linear-gradient(90deg,#5FD0C0,var(--acc));width:0;transition:width .55s ease}
.pane{flex:1 1 auto;position:relative;overflow:hidden;opacity:0}
.pane.in{animation:fadeup .5s ease forwards}
@keyframes fadeup{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:none}}
.pane.center{display:flex;align-items:center;justify-content:center;text-align:center;padding:22px}
.nav{flex:0 0 auto;display:flex;justify-content:space-between;align-items:center;padding:12px 22px;border-top:1px solid #eef2f6;background:#fff}
.btn{background:var(--acc);color:#fff;border:0;border-radius:10px;padding:12px 24px;font-size:15px;font-weight:700;cursor:pointer;transition:transform .15s,box-shadow .15s;box-shadow:0 6px 16px rgba(14,124,134,.28);font-family:inherit}
.btn:hover{transform:translateY(-2px);box-shadow:0 10px 22px rgba(14,124,134,.36)}
.btn.alt{background:#fff;color:var(--acc);border:1px solid #cfe3e3;box-shadow:none}
.btn[disabled]{opacity:.35;cursor:default;transform:none;box-shadow:none}
.kick{color:var(--acc);letter-spacing:2px;font-size:12px;font-weight:800;text-transform:uppercase}
h2{font-family:Georgia,serif;color:#0E2233;font-size:26px;margin:8px 0 14px;line-height:1.15}
p{font-size:15px;line-height:1.62;color:#2b3340;margin:0 0 12px}
svg .pz{transform-origin:center;transform-box:fill-box;animation:pz 2.6s ease-in-out infinite}
@keyframes pz{0%,100%{transform:scale(1)}50%{transform:scale(1.12)}}
.two{display:flex;height:100%}
.two .left{position:relative;flex:0 0 44%;overflow:hidden;background:#0E2233}
.two .right{flex:1 1 auto;padding:26px 34px;overflow:hidden;display:flex;flex-direction:column}
.hero{position:absolute;inset:0;overflow:hidden}
.hero .kb{position:absolute;inset:-5%;background-size:cover;background-position:center;animation:kb 20s ease-in-out infinite alternate}
.hero .kb.ph{background:linear-gradient(135deg,#0E2233,var(--acc))}
@keyframes kb{from{transform:scale(1) translate(0,0)}to{transform:scale(1.12) translate(-1.5%,-1%)}}
.right .scroll{overflow:auto;padding-right:8px}
.meta{margin-top:auto;color:#8a98a4;font-size:12px;padding-top:12px}
.kp{background:#F1F7F8;border-left:4px solid var(--acc);border-radius:8px;padding:12px 16px;margin:12px 0}
.kp .kph{font-weight:800;color:#0E2233;font-size:13px;display:flex;align-items:center;gap:8px;margin-bottom:6px}
.kp .kph svg{width:18px;height:18px}
.kp ul{margin:0;padding-left:18px}.kp li{font-size:14px;line-height:1.5;margin:5px 0}
.badge{position:absolute;left:18px;bottom:18px;width:56px;height:56px;background:rgba(255,255,255,.94);border-radius:15px;display:flex;align-items:center;justify-content:center;box-shadow:0 10px 24px rgba(0,0,0,.28)}
.badge svg{width:32px;height:32px}
.cover{position:absolute;inset:0;color:#fff}
.cover .cbg{position:absolute;inset:0;background-size:cover;background-position:center;animation:kb 24s ease-in-out infinite alternate}
.cover .cbg.ph{background:linear-gradient(135deg,#0E2233,var(--acc))}
.cover .cgrad{position:absolute;inset:0;background:linear-gradient(90deg,rgba(8,18,28,.93),rgba(8,18,28,.55) 55%,rgba(8,18,28,.18))}
.cover .cinner{position:absolute;left:7%;right:28%;top:50%;transform:translateY(-50%)}
.ckick{letter-spacing:3px;font-size:13px;font-weight:800;text-transform:uppercase;color:#7fe0d2;animation:fadeup .6s .1s both}
.ctitle{font-size:42px;line-height:1.05;margin:12px 0 14px;font-weight:800;animation:fadeup .6s .25s both}
.csub{font-size:16px;line-height:1.5;color:#dcebf0;animation:fadeup .6s .4s both}
.cact{margin-top:22px;animation:fadeup .6s .55s both}
.namewrap{max-width:520px}
.nicon{width:64px;height:64px;margin:0 auto 8px}.nicon svg{width:64px;height:64px}
.ninput{width:100%;padding:14px 16px;font-size:16px;border:1px solid #cfe0e0;border-radius:10px;margin-top:14px;outline:none;font-family:inherit}
.ninput:focus{border-color:var(--acc);box-shadow:0 0 0 3px rgba(14,124,134,.25)}
.nerr{color:#B02525;font-size:13px;margin-top:8px;min-height:16px}
.mission{list-style:none;margin:14px 0 0;padding:0;text-align:left}
.mission li{display:flex;align-items:center;gap:12px;padding:9px 0;border-bottom:1px solid #eef2f6;font-size:14.5px;color:#2b3340}
.mission li .mn{flex:0 0 26px;height:26px;border-radius:50%;background:var(--acc);color:#fff;font-weight:800;font-size:12px;display:flex;align-items:center;justify-content:center}
.mission li .mx{margin-left:auto;font-size:11px;letter-spacing:1px;color:#8a98a4;font-weight:700;text-transform:uppercase}
.mission li.game .mn{background:var(--gold);color:#0E2233}
.quiz,.review{padding:26px 38px;overflow:auto;height:100%;width:100%;text-align:left}
.q{margin:0 0 16px}.q .qt{font-weight:700;color:#0E2233;margin-bottom:8px;font-size:15px}
.opt{display:flex;align-items:center;gap:10px;border:1px solid #dde6ec;border-radius:10px;padding:11px 14px;margin:7px 0;cursor:pointer;font-size:14px;transition:border-color .15s,background .15s}
.opt:hover{border-color:var(--acc);background:#f7fbfb}.opt input{accent-color:var(--acc)}
.ans{background:#F1F7F8;border-left:4px solid #1E8E5A;border-radius:8px;padding:10px 14px;font-size:14px}.ans span{color:#5A6472;font-size:13px}
.ans.wrong{background:#FDECEC;border-left-color:#B02525}.ans .yr{color:#B02525;font-weight:700;font-size:13px;margin-bottom:5px}
.ring{position:relative;width:150px;height:150px;margin:0 auto 14px}
.ring svg{width:150px;height:150px;transform:rotate(-90deg)}
.ring .rbg{fill:none;stroke:#e7eef0;stroke-width:10}
.ring .rfg{fill:none;stroke-width:10;stroke-linecap:round}
.ring .rfg.p{stroke:#1E8E5A}.ring .rfg.f{stroke:#B02525}
.ring .rscore{position:absolute;inset:0;display:flex;align-items:center;justify-content:center;font-size:36px;font-weight:800;color:#0E2233}
.pill{display:inline-block;padding:5px 14px;border-radius:14px;font-size:12px;font-weight:800;letter-spacing:.5px}
.pill.pass{background:#E4F6EC;color:#1E8E5A}.pill.fail{background:#FDECEC;color:#B02525}
.statrow{display:flex;gap:12px;justify-content:center;margin:10px 0 4px;flex-wrap:wrap}
.stat{background:#F1F7F8;border:1px solid #e3ecee;border-radius:12px;padding:10px 18px;min-width:104px}
.stat .sv{font-size:21px;font-weight:800;color:#0E2233}.stat .sl{font-size:10px;letter-spacing:1.5px;text-transform:uppercase;color:#8a98a4;font-weight:700;margin-top:2px}
.medals{display:flex;gap:10px;justify-content:center;margin:12px 0 2px;flex-wrap:wrap}
.medal{display:flex;flex-direction:column;align-items:center;gap:4px;width:86px}
.medal .mi{width:46px;height:46px;border-radius:50%;background:linear-gradient(135deg,#F6E6A8,#D9B45A);display:flex;align-items:center;justify-content:center;font-size:22px;box-shadow:0 5px 12px rgba(169,132,47,.35);animation:pop .45s ease both}
.medal.off .mi{background:#eef2f6;box-shadow:none;filter:grayscale(1);opacity:.45}
.medal .ml{font-size:10px;font-weight:700;color:#46505c;text-align:center;line-height:1.25}
.toast{position:absolute;left:20px;bottom:78px;z-index:60;background:#0E2233;color:#fff;border-left:4px solid var(--gold);border-radius:10px;padding:11px 16px;font-size:13px;box-shadow:0 12px 30px rgba(0,0,0,.4);display:flex;align-items:center;gap:10px;transform:translateX(-130%);transition:transform .4s cubic-bezier(.2,.9,.3,1.2)}
.toast.show{transform:none}
.toast .te{font-size:20px}.toast b{color:#F6E6A8}
/* ---- game ---- */
.gwrap{position:absolute;inset:0;background:#060f18;overflow:hidden}
#g3d{position:absolute;inset:0}
#g3d canvas{display:block}
.ghud{position:absolute;inset:0;pointer-events:none;display:flex;flex-direction:column;color:#eaf4f8}
.gtop{display:flex;align-items:center;gap:16px;padding:13px 20px;font-weight:800}
.gscore{font-size:22px;color:#fff;min-width:70px}
.gcombo{font-size:12px;color:var(--gold);letter-spacing:1px;min-width:70px}
.gwave{font-size:11px;letter-spacing:2px;text-transform:uppercase;color:#9fe4d8}
