.gbtns{display:flex;gap:14px;justify-content:center;padding:14px 0 20px;pointer-events:auto}
.gbtn{border:0;border-radius:12px;padding:14px 26px;font-size:15px;font-weight:800;cursor:pointer;font-family:inherit;letter-spacing:.4px;transition:transform .12s,box-shadow .12s;box-shadow:0 8px 22px rgba(0,0,0,.45)}
.gbtn:hover{transform:translateY(-2px)}
