.gkeys{text-align:center;font-size:10.5px;color:#7e93a0;letter-spacing:1px;padding-bottom:10px}
.gover{position:absolute;inset:0;z-index:40;display:flex;align-items:center;justify-content:center;background:rgba(4,10,17,.84);backdrop-filter:blur(3px)}
.gcard{background:#0E2233;border:1px solid rgba(159,228,216,.25);border-radius:16px;padding:30px 38px;text-align:center;max-width:520px;color:#eaf4f8;box-shadow:0 24px 60px rgba(0,0,0,.55);animation:pop .45s ease both}
