.cert .present{font-style:italic;color:#5A6472;font-size:13px}
.cert .name{font-size:40px;color:#0E2233;line-height:1.05;margin:2px 0 4px;font-weight:700}
.cert .nund{width:260px;height:2px;background:linear-gradient(90deg,transparent,#C9A24B 20%,#C9A24B 80%,transparent);margin-bottom:6px}
.cert .forr{font-style:italic;color:#5A6472;font-size:13px}
.cert .course{font-size:19px;color:var(--acc);font-weight:700;line-height:1.18;margin-top:3px;max-width:90%}
.cert .ach{font-size:12px;color:#5A6472;margin-top:6px;font-family:Arial,sans-serif}.cert .ach b{color:#0E2233}
.cert .footer{width:100%;display:flex;align-items:flex-end;justify-content:space-between}
.cert .sig{width:190px;text-align:center}.cert .sig .sline{height:1px;background:#9aa6b2;margin-bottom:5px}.cert .sig .snm{font-style:italic;font-size:15px;color:#0E2233}.cert .sig .slb{font-size:9px;letter-spacing:1px;color:#8a98a4;font-family:Arial,sans-serif;text-transform:uppercase;margin-top:2px}
.cert .sealwrap{width:118px;display:flex;justify-content:center;flex:0 0 auto}.cert .seal{width:106px;height:122px;filter:drop-shadow(0 6px 10px rgba(0,0,0,.22))}
