 host.appendChild(renderer.domElement);
 var scene=new THREE.Scene();scene.background=new THREE.Color(0x060f18);scene.fog=new THREE.FogExp2(0x060f18,0.026);
 var cam=new THREE.PerspectiveCamera(58,W/H,0.1,300);cam.position.set(0,2.6,9.5);cam.lookAt(0,1.4,-20);
 scene.add(new THREE.AmbientLight(0x90a8b8,.75));
 var dl=new THREE.DirectionalLight(0xffffff,.85);dl.position.set(5,9,7);scene.add(dl);
 var pl=new THREE.PointLight(hexInt(TH.acc),1.1,40);pl.position.set(0,4,-4);scene.add(pl);
 var grid=new THREE.GridHelper(260,86,hexInt(TH.acc),0x123042);grid.position.y=-1.4;scene.add(grid);
 var sg=new THREE.BufferGeometry();var sp=new Float32Array(750*3);
 for(var i=0;i<750;i++){sp[i*3]=(Math.random()-.5)*160;sp[i*3+1]=Math.random()*40-4;sp[i*3+2]=-Math.random()*220;}
 sg.setAttribute('position',new THREE.BufferAttribute(sp,3));
 var stars=new THREE.Points(sg,new THREE.PointsMaterial({color:0x9fe4d8,size:.5,transparent:true,opacity:.65}));scene.add(stars);
 var fw=new THREE.Mesh(new THREE.PlaneGeometry(40,10),new THREE.MeshBasicMaterial({color:hexInt(TH.acc),transparent:true,opacity:.13,side:THREE.DoubleSide,depthWrite:false}));
 fw.position.set(0,3.2,-7);scene.add(fw);
 var fwEdge=new THREE.LineSegments(new THREE.EdgesGeometry(fw.geometry),new THREE.LineBasicMaterial({color:hexInt(TH.acc),transparent:true,opacity:.6}));
 fwEdge.position.copy(fw.position);scene.add(fwEdge);
 var onR=function(){var w2=host.clientWidth,h2=host.clientHeight;if(!w2||!h2)return;cam.aspect=w2/h2;cam.updateProjectionMatrix();renderer.setSize(w2,h2);};
 window.addEventListener('resize',onR);
 GL.renderer=renderer;GL.scene=scene;GL.cam=cam;GL.onResize=onR;GL.host=host;
 GL.objs={grid:grid,stars:stars,fw:fw,fwEdge:fwEdge,parts:[],shake:0,t:0};
 return GL;
}catch(e){return null;}}
function makeLabel(text){var c=document.createElement('canvas');c.width=680;c.height=240;var x=c.getContext('2d');
 function rr(x0,y0,w,h,r){x.beginPath();x.moveTo(x0+r,y0);x.arcTo(x0+w,y0,x0+w,y0+h,r);x.arcTo(x0+w,y0+h,x0,y0+h,r);x.arcTo(x0,y0+h,x0,y0,r);x.arcTo(x0,y0,x0+w,y0,r);x.closePath();}
 rr(6,6,668,228,26);x.fillStyle='rgba(7,19,31,.95)';x.fill();x.lineWidth=5;x.strokeStyle=TH.acc;x.stroke();
 x.fillStyle='#eaf4f8';x.font='600 34px Arial';x.textAlign='center';x.textBaseline='middle';
 var words=String(text).split(' ');var lines=[];var line='';
 words.forEach(function(w){var t=line?(line+' '+w):w;if(x.measureText(t).width>600&&line){lines.push(line);line=w;}else line=t;});
 if(line)lines.push(line);lines=lines.slice(0,4);
 var lh=44,y0=120-((lines.length-1)*lh/2);
 lines.forEach(function(l,i){x.fillText(l,340,y0+i*lh);});
 var tex=new THREE.CanvasTexture(c);
 var m=new THREE.SpriteMaterial({map:tex,transparent:true});
 var s=new THREE.Sprite(m);s.scale.set(8.5,3,1);return s;}
function spawn3d(item){var g=new THREE.Group();
 var box=new THREE.Mesh(new THREE.BoxGeometry(2.6,1.6,.34),new THREE.MeshPhongMaterial({color:0x16384e,emissive:0x0a2840,shininess:70}));
 var edge=new THREE.LineSegments(new THREE.EdgesGeometry(box.geometry),new THREE.LineBasicMaterial({color:hexInt(TH.acc)}));
 g.add(box);g.add(edge);
 var lab=makeLabel(item.text);lab.position.set(0,2.5,0);g.add(lab);
 g.position.set((Math.random()*5-2.5),1.5,-95);
 GL.scene.add(g);
 return {group:g,box:box,passed:false};}
function burst3d(pos,col){var n=42;var geo=new THREE.BufferGeometry();var ps=new Float32Array(n*3);var vs=[];
 for(var i=0;i<n;i++){ps[i*3]=pos.x;ps[i*3+1]=pos.y;ps[i*3+2]=pos.z;vs.push({x:(Math.random()-.5)*16,y:(Math.random()-.2)*14,z:(Math.random()-.5)*10});}
 geo.setAttribute('position',new THREE.BufferAttribute(ps,3));
 var mat=new THREE.PointsMaterial({color:col,size:.6,transparent:true,opacity:1});
 var pts=new THREE.Points(geo,mat);GL.scene.add(pts);
 GL.objs.parts.push({pts:pts,vs:vs,life:1});}
function glRun(){GL.running=true;var last=performance.now();
 (function loop(now){if(!GL.running)return;GL.raf=requestAnimationFrame(loop);
  var dt=Math.min((now-last)/1000,.06);last=now;var O=GL.objs;O.t+=dt;
  O.fw.material.opacity=.11+.05*Math.sin(O.t*2.6);
  O.fwEdge.material.opacity=.4+.25*Math.sin(O.t*2.6);
  O.grid.position.z=(O.t*7)%3;
  if(G.cur&&G.cur.gl&&!G.over){var sp=(G.wave===2?20:14.5);
   G.cur.gl.group.position.z+=sp*dt;
   if(!G.decided&&G.cur.gl.group.position.z>=-7){decide('allow',true);}
   if(G.cur.gl.passed){G.cur.gl.group.position.z+=14*dt;if(G.cur.gl.group.position.z>14){GL.scene.remove(G.cur.gl.group);G.cur.gl=null;}}}
  for(var i=O.parts.length-1;i>=0;i--){var P=O.parts[i];P.life-=dt*1.6;
   var arr=P.pts.geometry.attributes.position.array;
   for(var k=0;k<P.vs.length;k++){arr[k*3]+=P.vs[k].x*dt;arr[k*3+1]+=P.vs[k].y*dt;arr[k*3+2]+=P.vs[k].z*dt;P.vs[k].y-=9*dt;}
   P.pts.geometry.attributes.position.needsUpdate=true;P.pts.material.opacity=Math.max(P.life,0);
   if(P.life<=0){GL.scene.remove(P.pts);O.parts.splice(i,1);}}
  if(O.shake>0){O.shake-=dt;GL.cam.position.x=(Math.random()-.5)*O.shake*1.6;GL.cam.position.y=2.6+(Math.random()-.5)*O.shake*1.2;}
  else {GL.cam.position.x=0;GL.cam.position.y=2.6;}
  GL.renderer.render(GL.scene,GL.cam);})(last);}
