function spawn2d(item){var host=gEl('g3d');var el=document.createElement('div');el.className='gpkt';el.textContent=item.text;
 el.style.top='-90px';host.appendChild(el);
 var lane=host.clientHeight||400;var yEnd=lane*.74-40;
 var dur=(G.wave===2?5200:7200);
 G2.el=el;G2.y0=-90;G2.y1=yEnd;G2.t0=performance.now();G2.dur=dur;
 (function step(now){if(!G2.el||G.over)return;var k=Math.min((now-G2.t0)/G2.dur,1);
  G2.el.style.top=(G2.y0+(G2.y1-G2.y0)*k)+'px';
