  G2.timer=requestAnimationFrame(step);})(performance.now());}
function clear2d(){if(G2.timer)cancelAnimationFrame(G2.timer);G2.timer=0;if(G2.el&&G2.el.parentNode)G2.el.parentNode.removeChild(G2.el);G2.el=null;}
/* --- core game flow --- */
function nextPacket(){if(G.over)return;
 if(G.idx>0&&G.idx===gWaveSize()&&G.wave===1){if(G.waveClean)badge('perfect');G.wave=2;G.waveClean=true;updHud();gMsg('Wave 2 \\u2014 incoming faster!','ok','');sfx('lvl');
  setTimeout(launchCur,1300);return;}
 launchCur();}
function launchCur(){if(G.over)return;
 if(G.idx>=G.items.length)return endGame(true);
 var item=G.items[G.idx];G.cur={item:item,gl:null};G.decided=false;setBtns(true);gMsg('','','');
 if(G.mode==='3d'&&GL.scene)G.cur.gl=spawn3d(item);else spawn2d(item);}
function decide(action,auto){if(!G.cur||G.decided||G.over)return;G.decided=true;setBtns(false);
 var it=G.cur.item;var correct=(action==='block')===!!it.risky;
 var speedBonus=0;
 if(G.mode==='3d'&&G.cur.gl){var z=G.cur.gl.group.position.z;speedBonus=Math.max(0,Math.min(50,Math.round((-z-7)/85*50)));}
 else if(G2.el){var k=(performance.now()-G2.t0)/G2.dur;speedBonus=Math.max(0,Math.min(50,Math.round((1-k)*50)));}
 G.n++;
 if(correct){G.ok++;G.combo++;if(G.combo>=5)badge('combo');
  var mult=1+Math.min(G.combo*.1,1);var pts=Math.round((100+speedBonus)*mult);G.score+=pts;
  if(action==='block'){sfx('zap');
   if(G.cur.gl){burst3d(G.cur.gl.group.position,hexInt(TH.gold));GL.scene.remove(G.cur.gl.group);G.cur.gl=null;}
   else clear2d();
   gMsg('\\u26A1 Threat blocked &nbsp;+'+pts,'ok',it.why);}
  else {sfx('ok');
   if(G.cur.gl){G.cur.gl.box.material.emissive.setHex(0x1E8E5A);G.cur.gl.passed=true;}
   else clear2d();
   gMsg('\\u2714 Safe \\u2014 allowed through &nbsp;+'+pts,'ok',it.why);}}
 else {G.combo=0;G.integrity-=25;G.waveClean=false;sfx('bad');
  var fl=gEl('gflash');if(fl){fl.classList.add('on');setTimeout(function(){fl.classList.remove('on');},420);}
  if(GL.objs)GL.objs.shake=.5;
  if(G.cur.gl){burst3d(G.cur.gl.group.position,0xB02525);GL.scene.remove(G.cur.gl.group);G.cur.gl=null;}
  else clear2d();
  gMsg(it.risky?'\\u2718 Breach! That was a threat':'\\u2718 False alarm \\u2014 that one was safe','bad',it.why);}
 updHud();
 if(G.integrity<=0){setTimeout(function(){endGame(false);},1400);return;}
 G.idx++;
 setTimeout(nextPacket,1750);}
