 qs.forEach(function(q,qi){h+='<div class="q"><div class="qt">'+(qi+1)+'. '+esc(q.q)+'</div>';(q.options||[]).forEach(function(o,oi){h+='<label class="opt"><input type="radio" name="q'+qi+'" value="'+oi+'"><span>'+esc(o)+'</span></label>';});h+='</div>';});
