 + '  xsi:schemaLocation="http://www.imsproject.org/xsd/imscp_rootv1p1p2 imscp_rootv1p1p2.xsd http://www.imsglobal.org/xsd/imsmd_rootv1p2p1 imsmd_rootv1p2p1.xsd http://www.adlnet.org/xsd/adlcp_rootv1p2 adlcp_rootv1p2.xsd">\n'
 + '  <metadata><schema>ADL SCORM</schema><schemaversion>1.2</schemaversion></metadata>\n'
 + '  <organizations default="' + xml(orgId) + '">\n'
 + '    <organization identifier="' + xml(orgId) + '">\n'
 + '      <title>' + xml(courseTitle) + '</title>\n'
 + '      <item identifier="item_1" identifierref="res_1" isvisible="true">\n'
 + '        <title>' + xml(courseTitle) + '</title>\n'
 + '        <adlcp:masteryscore>' + (Number(meta.passMark) || 80) + '</adlcp:masteryscore>\n'
 + '      </item>\n'
 + '    </organization>\n'
 + '  </organizations>\n'
 + '  <resources>\n'
 + '    <resource identifier="res_1" type="webcontent" adlcp:scormtype="sco" href="index.html">\n'
 + '      <file href="index.html"/>\n'
 + '    </resource>\n'
 + '  </resources>\n'
 + '</manifest>\n';

const wantHtml = (format !== 'SCORM');
const wantScorm = (format !== 'HTML');
let htmlPath = '', zipPath = '';
let wrote = false;
if (wantHtml) { try { fs.writeFileSync(dir + '/' + base + '.html', html); htmlPath = dir + '/' + base + '.html'; wrote = true; } catch (e) {} }
if (wantScorm) {
  try {
    const zip = zipStore([{ name: 'imsmanifest.xml', data: manifest }, { name: 'index.html', data: html }]);
    fs.writeFileSync(dir + '/' + base + '-scorm.zip', zip); zipPath = dir + '/' + base + '-scorm.zip'; wrote = true;
  } catch (e) {}
}
if (!wrote) throw new Error('Learning Hub course: could not write to ' + dir + '. Make /reports writable by the n8n container, e.g. `chmod -R a+rwX reports` on the host.');
const bin = await this.helpers.prepareBinaryData(html, base + '.html', 'text/html');
return [{ json: { ok: true, dir: dir, file: htmlPath || zipPath, html: htmlPath, scorm: zipPath, topic: meta.topic, title: meta.title, format: format, hasGame: !!meta.hasGame, publicationId: meta.publicationId, courseId: meta.courseId }, binary: { data: bin } }];
